import { chromium } from 'playwright';
import { setTimeout } from 'timers/promises';

(async () => {
  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  const page = await context.newPage();

  console.log('Navigating to Storybook Voucher Form story...');
  await page.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form');

  // Wait for page to load
  await page.waitForLoadState('networkidle');
  await setTimeout(2000);

  console.log('Looking for dark mode toggle...');

  // Try to find the theme toggle button in the toolbar
  // Storybook typically uses a sun/moon icon button in the toolbar
  const themeToggleSelectors = [
    'button[title="Change the theme of the preview"]',
    'button[aria-label="Change the theme of the preview"]',
    'button[title*="theme"]',
    'button[aria-label*="theme"]',
    '[data-testid="theme-toggle"]',
    // Look for sun/moon SVG icons
    'button:has(svg[class*="sun"])',
    'button:has(svg[class*="moon"])',
    // Generic toolbar buttons
    'div[role="toolbar"] button',
  ];

  let themeButton = null;
  for (const selector of themeToggleSelectors) {
    try {
      const element = page.locator(selector).first();
      if (await element.count() > 0) {
        console.log(`Found potential theme toggle with selector: ${selector}`);
        themeButton = element;
        break;
      }
    } catch (e) {
      // Continue to next selector
    }
  }

  if (themeButton) {
    console.log('Clicking theme toggle button...');
    await themeButton.click();
    await setTimeout(2000);

    console.log('Taking screenshot after toggle...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle.png',
      fullPage: true
    });
    console.log('Screenshot saved to .storybook/screenshots/editor-dark-toggle.png');
  } else {
    console.log('Could not find theme toggle button automatically.');
    console.log('Taking screenshot of current state...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-before-toggle.png',
      fullPage: true
    });
  }

  // Try the URL with dark background parameter
  console.log('\nTrying URL with dark background parameter...');
  await page.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form&globals=backgrounds.value:dark');
  await page.waitForLoadState('networkidle');
  await setTimeout(2000);

  console.log('Taking screenshot with dark background parameter...');
  await page.screenshot({
    path: '.storybook/screenshots/editor-dark-url-param.png',
    fullPage: true
  });
  console.log('Screenshot saved to .storybook/screenshots/editor-dark-url-param.png');

  // Try to inspect toolbar buttons
  console.log('\nInspecting toolbar structure...');
  const toolbarButtons = await page.locator('div[role="toolbar"] button').all();
  console.log(`Found ${toolbarButtons.length} toolbar buttons`);

  for (let i = 0; i < toolbarButtons.length && i < 10; i++) {
    const title = await toolbarButtons[i].getAttribute('title');
    const ariaLabel = await toolbarButtons[i].getAttribute('aria-label');
    console.log(`Button ${i}: title="${title}", aria-label="${ariaLabel}"`);
  }

  await browser.close();
  console.log('\nDone!');
})();

import { chromium } from 'playwright';
import { setTimeout } from 'timers/promises';

(async () => {
  const browser = await chromium.launch({ headless: false });
  const context = await browser.newContext();
  const page = await context.newPage();

  console.log('Navigating to Storybook...');
  await page.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form');
  await page.waitForLoadState('networkidle');
  await setTimeout(2000);

  console.log('\nSearching for theme-related elements...');

  // Try to find all buttons on the page
  const allButtons = await page.locator('button').all();
  console.log(`\nFound ${allButtons.length} total buttons on the page`);

  // Look for buttons that might be theme toggles
  for (let i = 0; i < allButtons.length; i++) {
    const btn = allButtons[i];
    const title = await btn.getAttribute('title');
    const ariaLabel = await btn.getAttribute('aria-label');
    const id = await btn.getAttribute('id');
    const className = await btn.getAttribute('class');
    const innerHTML = await btn.evaluate(el => el.innerHTML);

    // Filter for potentially relevant buttons
    if (
      (title && (title.toLowerCase().includes('theme') || title.toLowerCase().includes('dark') || title.toLowerCase().includes('background'))) ||
      (ariaLabel && (ariaLabel.toLowerCase().includes('theme') || ariaLabel.toLowerCase().includes('dark') || ariaLabel.toLowerCase().includes('background'))) ||
      innerHTML.toLowerCase().includes('sun') ||
      innerHTML.toLowerCase().includes('moon')
    ) {
      console.log(`\n=== Button ${i} ===`);
      console.log(`Title: ${title}`);
      console.log(`Aria-label: ${ariaLabel}`);
      console.log(`ID: ${id}`);
      console.log(`Class: ${className}`);
      console.log(`HTML: ${innerHTML.substring(0, 200)}`);
    }
  }

  // Check for storybook-specific selectors
  console.log('\n\nChecking Storybook-specific selectors...');
  const storybookSelectors = [
    '#storybook-preview-wrapper',
    '[data-side="right"]',
    '.sidebar-container',
    '#storybook-panel-root',
    '[id*="addon"]',
  ];

  for (const selector of storybookSelectors) {
    const count = await page.locator(selector).count();
    if (count > 0) {
      console.log(`Found ${count} element(s) matching: ${selector}`);
    }
  }

  // Look for the backgrounds addon specifically
  console.log('\n\nLooking for backgrounds addon...');
  const addonsPanel = page.locator('#storybook-panel-root');
  if (await addonsPanel.count() > 0) {
    console.log('Found addons panel');

    // Try to find and click the "Backgrounds" tab
    const backgroundsTab = page.locator('button:has-text("Backgrounds")');
    if (await backgroundsTab.count() > 0) {
      console.log('Found Backgrounds tab, clicking it...');
      await backgroundsTab.click();
      await setTimeout(1000);

      // Take screenshot of backgrounds panel
      await page.screenshot({
        path: '.storybook/screenshots/backgrounds-panel.png',
        fullPage: true
      });
      console.log('Screenshot saved: backgrounds-panel.png');
    }
  }

  // Try clicking on toolbar area icons
  console.log('\n\nLooking for toolbar icons...');
  const toolbar = page.locator('[role="toolbar"]').first();
  if (await toolbar.count() > 0) {
    console.log('Found toolbar');
    const toolbarHTML = await toolbar.evaluate(el => el.innerHTML);
    console.log('Toolbar HTML:', toolbarHTML.substring(0, 500));
  }

  // Keep browser open for manual inspection
  console.log('\n\nBrowser will stay open for 30 seconds for manual inspection...');
  await setTimeout(30000);

  await browser.close();
  console.log('Done!');
})();

import { chromium } from 'playwright';
import { setTimeout } from 'timers/promises';

(async () => {
  const browser = await chromium.launch({
    headless: false,
    slowMo: 100 // Slow down for better visibility
  });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 }
  });
  const page = await context.newPage();

  try {
    console.log('Step 1: Navigate to Storybook Voucher Form story...');
    await page.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form');
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);

    console.log('Step 2: Taking initial screenshot (light mode)...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle-before.png',
      fullPage: true
    });

    console.log('Step 3: Looking for theme toggle in toolbar...');

    // Storybook 7+ typically has a toolbar with theme controls
    // Try multiple strategies to find and click the dark mode toggle

    // Strategy 1: Look for a button with 'theme' in title or aria-label
    let clicked = false;
    const themeButtonSelectors = [
      'button[title*="Change theme"]',
      'button[title*="theme"]',
      'button[aria-label*="theme"]',
      'button[aria-label*="Change theme"]',
      'button[title="Change the background of the preview"]',
      'button[aria-label="Change the background of the preview"]',
    ];

    for (const selector of themeButtonSelectors) {
      try {
        const button = page.locator(selector).first();
        if (await button.count() > 0) {
          console.log(`Found theme button with selector: ${selector}`);
          await button.click();
          clicked = true;
          break;
        }
      } catch (e) {
        // Try next selector
      }
    }

    // Strategy 2: Try to find and click on addon panel tabs
    if (!clicked) {
      console.log('Strategy 2: Looking for addon panels...');

      // Click on "Addons" tab if visible
      const addonsTab = page.locator('button[role="tab"]:has-text("Addons")');
      if (await addonsTab.count() > 0) {
        console.log('Found Addons tab');
        await addonsTab.click();
        await setTimeout(1000);
      }

      // Look for "Backgrounds" in the addons
      const backgroundsControl = page.locator('button:has-text("Backgrounds")');
      if (await backgroundsControl.count() > 0) {
        console.log('Found Backgrounds control');
        await backgroundsControl.click();
        await setTimeout(1000);
        clicked = true;
      }
    }

    // Strategy 3: Try keyboard shortcut (if Storybook supports it)
    if (!clicked) {
      console.log('Strategy 3: Trying keyboard shortcuts...');
      // Some versions of Storybook support shortcuts for theme switching
      await page.keyboard.press('Meta+Alt+t');
      await setTimeout(1000);
    }

    // Strategy 4: Use URL parameters to force dark mode
    console.log('Strategy 4: Using URL parameter to enable dark mode...');
    await page.goto('http://localhost:6006/?path=/story/sdui-demo-voucher--form&globals=backgrounds.value:dark');
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);

    console.log('Taking screenshot with dark mode URL parameter...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle.png',
      fullPage: true
    });
    console.log('✓ Screenshot saved: editor-dark-toggle.png');

    // Strategy 5: Try injecting dark mode via JavaScript
    console.log('Strategy 5: Trying to inject dark mode via JavaScript...');
    await page.evaluate(() => {
      // Try to find and modify the iframe's background
      const preview = document.querySelector('#storybook-preview-iframe');
      if (preview && preview.contentDocument) {
        const body = preview.contentDocument.body;
        if (body) {
          body.style.backgroundColor = '#1a1a1a';
          body.style.color = '#ffffff';
        }
      }

      // Try to add dark mode class to root
      const root = document.documentElement;
      root.classList.add('dark');
      root.setAttribute('data-theme', 'dark');

      // Try to change Storybook's theme
      try {
        const storybookRoot = document.querySelector('#storybook-root');
        if (storybookRoot) {
          storybookRoot.classList.add('dark');
        }
      } catch (e) {
        console.log('Could not modify Storybook root');
      }
    });

    await setTimeout(2000);

    console.log('Taking screenshot after JS injection...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle-injected.png',
      fullPage: true
    });
    console.log('✓ Screenshot saved: editor-dark-toggle-injected.png');

    // Take one more with just the preview iframe
    console.log('Taking screenshot of preview iframe only...');
    const previewFrame = page.frameLocator('#storybook-preview-iframe');
    if (previewFrame) {
      await page.locator('#storybook-preview-iframe').screenshot({
        path: '.storybook/screenshots/editor-dark-toggle-preview-only.png'
      });
      console.log('✓ Screenshot saved: editor-dark-toggle-preview-only.png');
    }

    console.log('\n=== Summary ===');
    console.log('Screenshots captured:');
    console.log('  1. editor-dark-toggle-before.png (initial state)');
    console.log('  2. editor-dark-toggle.png (with URL parameter)');
    console.log('  3. editor-dark-toggle-injected.png (with JS injection)');
    console.log('  4. editor-dark-toggle-preview-only.png (preview iframe only)');

  } catch (error) {
    console.error('Error occurred:', error);
  } finally {
    await browser.close();
    console.log('\nDone!');
  }
})();

