import { chromium } from 'playwright';
import { setTimeout } from 'timers/promises';

(async () => {
  const browser = await chromium.launch({
    headless: false,
    slowMo: 50
  });
  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 }
  });
  const page = await context.newPage();

  try {
    console.log('=== STEP 1: Navigate to Voucher Form story ===');
    const storyUrl = 'http://localhost:6006/?path=/story/sdui-voucherdemo--form';
    console.log(`URL: ${storyUrl}`);
    await page.goto(storyUrl);
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);

    console.log('\n=== STEP 2: Take initial screenshot (light mode) ===');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle-before.png',
      fullPage: true
    });
    console.log('✓ Saved: editor-dark-toggle-before.png');

    console.log('\n=== STEP 3: Looking for theme toggle ===');

    // Look for Storybook toolbar buttons
    const toolbarButtons = await page.locator('[role="toolbar"] button').all();
    console.log(`Found ${toolbarButtons.length} toolbar buttons`);

    // Try to find a button with theme-related attributes
    let themeToggled = false;
    for (let i = 0; i < toolbarButtons.length; i++) {
      const btn = toolbarButtons[i];
      const title = await btn.getAttribute('title');
      const ariaLabel = await btn.getAttribute('aria-label');

      if (title || ariaLabel) {
        const text = `${title || ''} ${ariaLabel || ''}`.toLowerCase();
        if (text.includes('background') || text.includes('theme')) {
          console.log(`Found potential theme button: ${title || ariaLabel}`);
          await btn.click();
          await setTimeout(2000);
          themeToggled = true;

          // Look for dark option in dropdown/menu
          const darkOption = page.locator('button:has-text("dark"), [role="menuitem"]:has-text("dark"), [role="option"]:has-text("dark")').first();
          if (await darkOption.count() > 0) {
            console.log('Found dark option, clicking it...');
            await darkOption.click();
            await setTimeout(2000);
          }
          break;
        }
      }
    }

    if (themeToggled) {
      console.log('\n=== STEP 4: Taking screenshot after theme toggle ===');
      await page.screenshot({
        path: '.storybook/screenshots/editor-dark-toggle.png',
        fullPage: true
      });
      console.log('✓ Saved: editor-dark-toggle.png');
    } else {
      console.log('\n=== STEP 4: Theme toggle not found, using URL parameter ===');
    }

    // Alternative: Use URL parameter
    console.log('\n=== STEP 5: Using URL parameter for dark background ===');
    const darkUrl = 'http://localhost:6006/?path=/story/sdui-voucherdemo--form&globals=backgrounds.value:dark';
    console.log(`URL: ${darkUrl}`);
    await page.goto(darkUrl);
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);

    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle.png',
      fullPage: true
    });
    console.log('✓ Saved: editor-dark-toggle.png (with URL parameter)');

    console.log('\n=== SUMMARY ===');
    console.log('Screenshots created successfully:');
    console.log('  - .storybook/screenshots/editor-dark-toggle-before.png');
    console.log('  - .storybook/screenshots/editor-dark-toggle.png');

  } catch (error) {
    console.error('\n❌ Error:', error.message);
    throw error;
  } finally {
    await browser.close();
    console.log('\nBrowser closed.');
  }
})();

