(async () => {
  const browser = await chromium.launch({
    headless: false,
    slowMo: 100
  });

  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 },
    colorScheme: 'dark' // Request dark color scheme
  });

  const page = await context.newPage();

  try {
    console.log('=== Navigating to Voucher Form story ===');
    await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form');
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);

    console.log('\n=== Taking "before" screenshot ===');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle-before.png',
      fullPage: true
    });

    console.log('\n=== Inspecting toolbar structure ===');

    // Get all toolbar buttons and log them
    const toolbarArea = page.locator('#storybook-explorer-menu, [role="toolbar"], .css-*').first();
    const allButtons = await page.locator('button').all();

    console.log(`Total buttons on page: ${allButtons.length}`);

    // Look for any buttons that might toggle theme
    for (let i = 0; i < Math.min(allButtons.length, 30); i++) {
      const btn = allButtons[i];
      const title = await btn.getAttribute('title');
      const ariaLabel = await btn.getAttribute('aria-label');
      const id = await btn.getAttribute('id');

      if (title || ariaLabel) {
        console.log(`Button ${i}: title="${title}", aria="${ariaLabel}", id="${id}"`);
      }
    }

    // Try to toggle Storybook's theme using the UI
    console.log('\n=== Attempting to find and click theme/background toggle ===');

    // Look for common Storybook toolbar button selectors
    const possibleSelectors = [
      'button[title*="background"]',
      'button[title*="Background"]',
      'button[aria-label*="background"]',
      'button[aria-label*="Background"]',
      // Storybook's addon toolbar
      '[id*="addon-backgrounds"]',
      'button:has-text("Backgrounds")',
    ];

    let clicked = false;
    for (const selector of possibleSelectors) {
      const element = page.locator(selector).first();
      if (await element.count() > 0) {
        console.log(`Found element with selector: ${selector}`);
        await element.click();
        await setTimeout(1000);

        // Look for dark option in any opened menu
        const darkOptions = page.locator('[role="menuitem"]:has-text("dark"), button:has-text("dark"), [data-value="dark"]');
        if (await darkOptions.count() > 0) {
          console.log('Found dark option in menu');
          await darkOptions.first().click();
          await setTimeout(2000);
          clicked = true;
          break;
        }
      }
    }

    if (clicked) {
      console.log('\n=== Taking screenshot after UI toggle ===');
      await page.screenshot({
        path: '.storybook/screenshots/editor-dark-toggle.png',
        fullPage: true
      });
    }

    // Alternative: inject dark mode styles directly
    console.log('\n=== Injecting dark mode styles ===');
    await page.evaluate(() => {
      // Change the outer container background
      const container = document.querySelector('#storybook-root');
      if (container) {
        container.style.backgroundColor = '#1a1a1a';
      }

      // Try to find and modify the phone frame background
      const decorators = document.querySelectorAll('div[style*="backgroundColor"]');
      decorators.forEach(el => {
        if (el.style.backgroundColor === 'rgb(240, 240, 240)' ||
            el.style.backgroundColor === '#f0f0f0') {
          el.style.backgroundColor = '#1a1a1a';
        }
      });

      // Change preview background
      const preview = document.querySelector('#storybook-preview-wrapper');
      if (preview) {
        preview.style.backgroundColor = '#1a1a1a';
      }
    });

    await setTimeout(2000);

    console.log('\n=== Taking screenshot with injected dark styles ===');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle.png',
      fullPage: true
    });

    console.log('\n✓ Screenshots saved:');
    console.log('  - editor-dark-toggle-before.png');
    console.log('  - editor-dark-toggle.png');

  } catch (error) {
    console.error('Error:', error);
  } finally {
    await browser.close();
    console.log('\nDone.');
  }
})();

#!/usr/bin/env node
/**
 * Dark Mode Toggle Demo for Storybook
 *
 * This script automates the process of:
 * 1. Opening the Voucher Form story in Storybook
 * 2. Finding and clicking the theme/background toggle button
 * 3. Capturing before/after screenshots
 */

import { chromium } from 'playwright';
import { setTimeout } from 'timers/promises';

async function main() {
  console.log('╔══════════════════════════════════════════════════════════╗');
  console.log('║  Storybook Dark Mode Toggle Demo                        ║');
  console.log('╚══════════════════════════════════════════════════════════╝\n');

  const browser = await chromium.launch({
    headless: false,
    slowMo: 150 // Slow down for better visibility
  });

  const context = await browser.newContext({
    viewport: { width: 1920, height: 1080 }
  });

  const page = await context.newPage();

  try {
    // Step 1: Navigate to the story
    console.log('📖 Step 1: Navigating to Voucher Form story...');
    const storyUrl = 'http://localhost:6006/?path=/story/sdui-voucherdemo--form';
    await page.goto(storyUrl);
    await page.waitForLoadState('networkidle');
    await setTimeout(2000);
    console.log('   ✓ Story loaded\n');

    // Step 2: Take initial screenshot
    console.log('📸 Step 2: Capturing initial state...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle-before.png',
      fullPage: true
    });
    console.log('   ✓ Saved: editor-dark-toggle-before.png\n');

    // Step 3: Find the background toggle button
    console.log('🔍 Step 3: Locating background toggle button...');
    const backgroundButton = page.locator('button[title="Change the background of the preview"]').first();

    if (await backgroundButton.count() === 0) {
      console.log('   ⚠ Background toggle not found in toolbar');
      console.log('   Trying alternative URL with dark parameter...\n');

      await page.goto('http://localhost:6006/?path=/story/sdui-voucherdemo--form&globals=backgrounds.value:dark');
      await page.waitForLoadState('networkidle');
      await setTimeout(2000);
    } else {
      console.log('   ✓ Found background toggle button\n');

      // Step 4: Click the button to open the menu
      console.log('🖱️  Step 4: Clicking background toggle...');
      await backgroundButton.click();
      await setTimeout(1000);
      console.log('   ✓ Menu opened\n');

      // Step 5: Look for and click the dark option
      console.log('🌙 Step 5: Selecting dark background...');
      const darkOption = page.locator('[role="menuitem"]:has-text("dark"), button:has-text("dark")').first();

      if (await darkOption.count() > 0) {
        await darkOption.click();
        await setTimeout(2000);
        console.log('   ✓ Dark mode activated\n');
      } else {
        console.log('   ℹ No dark option found in menu\n');
      }
    }

    // Step 6: Take final screenshot
    console.log('📸 Step 6: Capturing dark mode state...');
    await page.screenshot({
      path: '.storybook/screenshots/editor-dark-toggle.png',
      fullPage: true
    });
    console.log('   ✓ Saved: editor-dark-toggle.png\n');

    // Summary
    console.log('╔══════════════════════════════════════════════════════════╗');
    console.log('║  ✨ Success!                                             ║');
    console.log('╠══════════════════════════════════════════════════════════╣');
    console.log('║  Screenshots saved:                                      ║');
    console.log('║    • editor-dark-toggle-before.png (light mode)          ║');
    console.log('║    • editor-dark-toggle.png (dark mode)                  ║');
    console.log('╚══════════════════════════════════════════════════════════╝\n');

  } catch (error) {
    console.error('\n❌ Error:', error.message);
    throw error;
  } finally {
    await browser.close();
  }
}

main().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});
